const { ApolloServer, gql } = require('apollo-server');
const { v4: uuidv4 } = require('uuid');

// Sample data
let users = [
  { id: '1', name: 'Alice' },
  { id: '2', name: 'Bob' }
];

let posts = [
  { id: '1', title: 'Post 1', content: 'Content 1', userId: '1' },
  { id: '2', title: 'Post 2', content: 'Content 2', userId: '2' }
];

let comments = [
  { id: '1', text: 'Comment 1', postId: '1', userId: '2' },
  { id: '2', text: 'Comment 2', postId: '1', userId: '1' }
];

// GraphQL schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    posts: [Post!]!
    comments: [Comment!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    user: User!
    comments: [Comment!]!
  }

  type Comment {
    id: ID!
    text: String!
    user: User!
    post: Post!
  }

  type Query {
    users: [User!]!
    posts: [Post!]!
    comments: [Comment!]!
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: () => users,
    posts: () => posts,
    comments: () => comments,
  },
  User: {
    posts: (user) => posts.filter(post => post.userId === user.id),
    comments: (user) => comments.filter(comment => comment.userId === user.id),
  },
  Post: {
    user: (post) => users.find(user => user.id === post.userId),
    comments: (post) => comments.filter(comment => comment.postId === post.id),
  },
  Comment: {
    user: (comment) => users.find(user => user.id === comment.userId),
    post: (comment) => posts.find(post => post.id === comment.postId),
  },
};

// Apollo Server setup
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Implement authentication and authorization logic here
    return { user: req.user || null };
  },
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});